# stream_mode="values" — emit full state after every node
for state in graph.stream({"question": "What is entropy?", "attempts": 0}, stream_mode="values"):
    print(f"Step state: confidence={state.get('confidence')}, attempts={state.get('attempts')}")

# stream_mode="updates" — emit only the dict returned by each node
for update in graph.stream({"question": "What is entropy?", "attempts": 0}, stream_mode="updates"):
    for node_name, node_output in update.items():
        print(f"[{node_name}] returned: {list(node_output.keys())}")

# stream_mode="debug" — emit every event (enter, exit, checkpoint)
for event in graph.stream({"question": "Explain ML?", "attempts": 0}, stream_mode="debug"):
    print(event["type"], event.get("step"))

class RobustState(TypedDict):
    query: str
    result: str
    error: str | None

def safe_llm_node(state: RobustState) -> dict:
    try:
        response = llm.invoke([HumanMessage(state["query"])])
        return {"result": response.content, "error": None}
    except Exception as e:
        return {"result": "", "error": str(e)}

def handle_error(state: RobustState) -> dict:
    return {"result": f"Could not answer due to: {state['error']}"}

def route_on_error(state: RobustState) -> str:
    return "error_handler" if state.get("error") else END

builder = StateGraph(RobustState)
builder.add_node("llm", safe_llm_node)
builder.add_node("error_handler", handle_error)
builder.add_edge(START, "llm")
builder.add_conditional_edges("llm", route_on_error, {"error_handler": "error_handler", END: END})
builder.add_edge("error_handler", END)

graph = builder.compile()
